mapper.select:
SELECT  FROM tsk_task t WHERE t.tenant_id=#{tenantId}
  AND t.project_id IN CAST(#{id} AS uuid)AND FALSE
  AND t.project_id=#{projectId}AND t.task_kind=#{taskKind}AND t.status=#{status}
  AND EXISTS(SELECT 1 FROM tsk_task_assignment a WHERE a.tenant_id=t.tenant_id AND a.task_id=t.task_id AND a.principal_type='USER' AND a.principal_id=#{assigneeId} AND a.status='ACTIVE')
  AND (t.priority < #{cursorPriority} OR (t.priority=#{cursorPriority} AND (t.next_run_at,t.created_at,t.task_id)>(#{cursorNextRunAt},#{cursorCreatedAt},#{cursorId})))
  ORDER BY t.priority DESC,t.next_run_at,t.created_at,t.task_id LIMIT #{fetchSize}

SELECT a.attempt_id AS "attemptId",a.attempt_no AS "attemptNo",a.result_code AS "resultCode",
       a.error_code AS "errorCode",a.result_ref AS "resultRef",a.next_retry_at AS "nextRetryAt",
       a.started_at AS "startedAt",a.finished_at AS "finishedAt"
  FROM tsk_task_execution_attempt a
  JOIN tsk_task t ON t.task_id=a.task_id AND t.tenant_id=#{tenantId}
 WHERE a.task_id=#{taskId}
 AND a.attempt_no < #{beforeAttemptNo}
 ORDER BY a.attempt_no DESC
 LIMIT #{fetchSize}
